import React, { useEffect, useState } from "react";
import axios from "axios";
import AdminNav from "./AdminNav";

const Categories = () => {
  const [items, setItems] = useState([]);
  const [error, setError] = useState("");
  const apiURL = process.env.REACT_APP_API_URL || "http://localhost:8000";

  useEffect(() => {
    const run = async () => {
      try {
        const raw = localStorage.getItem("adminJwt");
        if (!raw) { setError("Missing admin token"); return; }
        const { token } = JSON.parse(raw);
        const res = await axios.get(`${apiURL}/api/admin/categories`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        if (res.data && res.data.success) setItems(res.data.data);
        else setError(res.data.error || "Failed to load categories");
      } catch (err) {
        setError("Network or authorization error");
      }
    };
    run();
  }, [apiURL]);

  return (
    <div className="max-w-6xl mx-auto mt-10 p-6 border rounded">
      <h2 className="text-2xl font-semibold mb-4">Categories</h2>
      <AdminNav />
      {error && <div className="text-red-600 mb-3">{error}</div>}
      <div className="overflow-x-auto">
        <table className="min-w-full text-sm">
          <thead>
            <tr className="text-left">
              <th className="p-2">Name</th>
              <th className="p-2">Created</th>
            </tr>
          </thead>
          <tbody>
            {items.map((c) => (
              <tr key={c._id}>
                <td className="p-2">{c.cName || c.name}</td>
                <td className="p-2">{new Date(c.createdAt).toLocaleString()}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default Categories;
